// Extract MCP request body
const body = $input.item.json.body || $input.item.json;

// ---- MCP Schema Validation ----
const requiredFields = ['mcpVersion', 'clientId', 'apiKey', 'toolName', 'parameters'];
const missing = requiredFields.filter(f => !body[f]);
if (missing.length > 0) {
  throw new Error(`MCP Schema Violation — Missing required fields: ${missing.join(', ')}`);
}

// Validate MCP version compatibility
const supportedVersions = ['1.0', '1.1'];
if (!supportedVersions.includes(body.mcpVersion)) {
  throw new Error(`Unsupported MCP version: ${body.mcpVersion}. Supported: ${supportedVersions.join(', ')}`);
}

// ---- API Key Authentication ----
// In production, validate against a secrets store or database
const VALID_API_KEYS = [
  'mcp-key-prod-001',
  'mcp-key-prod-002',
  'mcp-key-dev-001'
];
if (!VALID_API_KEYS.includes(body.apiKey)) {
  throw new Error(`Authentication failed: Invalid API key for client '${body.clientId}'`);
}

// ---- Tool Name Format Validation ----
// MCP tool names must follow: category.action format
const toolNamePattern = /^[a-z][a-z0-9_]*\.[a-z][a-z0-9_]*$/;
if (!toolNamePattern.test(body.toolName)) {
  throw new Error(`Invalid tool name format: '${body.toolName}'. Must match pattern: category.action (e.g. crm.get_customer)`);
}

// ---- Parse tool category and action ----
const [toolCategory, toolAction] = body.toolName.split('.');

// ---- Build the normalized MCP request ----
const mcpRequest = {
  // MCP metadata
  gatewayRequestId: `GW-${Date.now()}-${Math.random().toString(36).substr(2, 9).toUpperCase()}`,
  mcpVersion: body.mcpVersion,
  requestId: body.requestId || `req-${Date.now()}`,
  clientId: body.clientId.trim(),
  apiKey: body.apiKey,

  // Tool identification
  toolName: body.toolName,
  toolCategory,
  toolAction,
  parameters: body.parameters,

  // Context and tracing
  callerContext: body.callerContext || null,
  sessionId: body.sessionId || null,
  traceId: body.traceId || `trace-${Date.now()}`,

  // Request metadata
  receivedAt: new Date().toISOString(),
  sourceIP: body.sourceIP || 'NOT_CAPTURED',
  userAgent: body.userAgent || 'MCP_CLIENT',

  // Permission scope requested
  requestedScope: body.requestedScope || 'read',
  dryRun: body.dryRun === true,

  // Status tracking
  status: 'AUTHENTICATED',
  processingStage: 'VALIDATION'
};

return { json: { mcpRequest } };

const mcpRequest = $('Validate Auth and MCP Schema').item.json.mcpRequest;
const registryResults = $('Lookup Tool in Registry').all();

// Check if tool exists in registry
if (!registryResults || registryResults.length === 0) {
  throw new Error(`Tool not found in registry: '${mcpRequest.toolName}'. Tool may be disabled or does not exist.`);
}

const toolConfig = registryResults[0].json;

// ---- Permission scope check ----
const scopeHierarchy = { 'read': 1, 'write': 2, 'admin': 3 };
const requiredScopeLevel = scopeHierarchy[toolConfig.requiredScope || 'read'] || 1;
const requestedScopeLevel = scopeHierarchy[mcpRequest.requestedScope] || 1;

if (requestedScopeLevel < requiredScopeLevel) {
  throw new Error(
    `Insufficient permissions: Tool '${mcpRequest.toolName}' requires scope '${toolConfig.requiredScope}' but client requested '${mcpRequest.requestedScope}'`
  );
}

// ---- Client allowlist check ----
const allowedClients = toolConfig.allowedClients
  ? toolConfig.allowedClients.split(',').map(c => c.trim())
  : [];
if (allowedClients.length > 0 && !allowedClients.includes(mcpRequest.clientId) && !allowedClients.includes('*')) {
  throw new Error(`Client '${mcpRequest.clientId}' is not authorized to call tool '${mcpRequest.toolName}'`);
}

// ---- Build resolved tool config ----
const resolvedTool = {
  toolName: toolConfig.toolName,
  toolCategory: toolConfig.toolCategory,
  toolDescription: toolConfig.description,
  backendUrl: toolConfig.backendUrl,
  httpMethod: toolConfig.httpMethod || 'GET',
  authType: toolConfig.authType || 'bearer',
  authSecretKey: toolConfig.authSecretKey || 'TOOL_API_TOKEN',
  requiredScope: toolConfig.requiredScope || 'read',
  parameterMapping: toolConfig.parameterMapping ? JSON.parse(toolConfig.parameterMapping) : {},
  responseMapping: toolConfig.responseMapping ? JSON.parse(toolConfig.responseMapping) : {},
  timeoutMs: parseInt(toolConfig.timeoutMs) || 10000,
  isMutating: toolConfig.isMutating === 'true',
  requiresConfirmation: toolConfig.requiresConfirmation === 'true',
  maxRetries: parseInt(toolConfig.maxRetries) || 1,
  rateLimit: parseInt(toolConfig.rateLimitPerMinute) || 60
};

return {
  json: {
    mcpRequest,
    resolvedTool,
    permissionsVerified: true,
    resolvedAt: new Date().toISOString()
  }
};

const aiResponse = $input.item.json;
let aiText = aiResponse.response || aiResponse.output || aiResponse.text || '';

// Handle Anthropic content array
if (aiResponse.content && Array.isArray(aiResponse.content)) {
  aiText = aiResponse.content[0]?.text || '';
}

const cleanText = aiText
  .replace(/```json\s*/g, '')
  .replace(/```\s*/g, '')
  .trim();

let intentVerification;
try {
  intentVerification = JSON.parse(cleanText);
} catch (error) {
  throw new Error(`Failed to parse Claude intent verification: ${error.message}. Raw: ${cleanText.substring(0, 200)}`);
}

// Pull upstream data
const upstream = $('Resolve Tool Config and Permissions').item.json;

// Hard block on CRITICAL risk or BLOCK recommendation
if (intentVerification.executionRecommendation === 'BLOCK' || intentVerification.riskLevel === 'CRITICAL') {
  throw new Error(
    `Tool call BLOCKED by AI safety guardrail: ${intentVerification.blockReason || 'Critical risk detected'}. Risk score: ${intentVerification.riskScore}`
  );
}

return {
  json: {
    mcpRequest: upstream.mcpRequest,
    resolvedTool: upstream.resolvedTool,
    intentVerification,
    proceedToExecution: intentVerification.safeToExecute && intentVerification.executionRecommendation !== 'BLOCK',
    requiresHumanGate: intentVerification.requiresHumanConfirmation || upstream.resolvedTool.requiresConfirmation,
    verifiedAt: new Date().toISOString()
  }
};

const upstream = $('Parse Intent Verification Result').item.json;
const rateLimitRecords = $('Check Rate Limit and Quota').all();

const now = new Date();
const oneMinuteAgo = new Date(now.getTime() - 60 * 1000);

// Count calls in the last 60 seconds for this client+tool
const recentCalls = rateLimitRecords.filter(r => {
  const callTime = new Date(r.json.calledAt);
  return callTime > oneMinuteAgo;
}).length;

const rateLimit = upstream.resolvedTool.rateLimit;

if (recentCalls >= rateLimit) {
  throw new Error(
    `Rate limit exceeded for client '${upstream.mcpRequest.clientId}' on tool '${upstream.mcpRequest.toolName}'. ` +
    `Limit: ${rateLimit}/min, Current: ${recentCalls}/min. Retry after 60 seconds.`
  );
}

// ---- Build mapped parameters for backend API ----
const rawParams = upstream.mcpRequest.parameters;
const paramMapping = upstream.resolvedTool.parameterMapping;

// Apply parameter name mapping (e.g. customerId -> customer_id for REST API)
const mappedParams = {};
for (const [key, value] of Object.entries(rawParams)) {
  const mappedKey = paramMapping[key] || key;
  mappedParams[mappedKey] = value;
}

// ---- Build execution context ----
const executionContext = {
  backendUrl: upstream.resolvedTool.backendUrl,
  httpMethod: upstream.resolvedTool.httpMethod,
  authType: upstream.resolvedTool.authType,
  authSecretKey: upstream.resolvedTool.authSecretKey,
  mappedParams,
  timeoutMs: upstream.resolvedTool.timeoutMs,
  isDryRun: upstream.mcpRequest.dryRun,
  isMutating: upstream.resolvedTool.isMutating,
  maxRetries: upstream.resolvedTool.maxRetries
};

return {
  json: {
    mcpRequest: upstream.mcpRequest,
    resolvedTool: upstream.resolvedTool,
    intentVerification: upstream.intentVerification,
    executionContext,
    rateLimitStatus: {
      recentCalls,
      limit: rateLimit,
      remaining: rateLimit - recentCalls - 1
    }
  }
};

const data = $input.item.json;

return {
  json: {
    isDryRun: true,
    dryRunResult: {
      wouldExecute: true,
      backendUrl: data.executionContext.backendUrl,
      httpMethod: data.executionContext.httpMethod,
      mappedParameters: data.executionContext.mappedParams,
      estimatedImpact: data.executionContext.isMutating ? 'DATA_MUTATION' : 'READ_ONLY',
      riskLevel: data.intentVerification.riskLevel,
      blastRadius: data.intentVerification.blastRadius,
      isReversible: data.intentVerification.isReversible
    },
    mcpRequest: data.mcpRequest,
    resolvedTool: data.resolvedTool,
    intentVerification: data.intentVerification
  }
};

// Handle both live execution and dry run paths
const isDryRun = $input.item.json.isDryRun || false;

let backendResponse, executionData;

if (isDryRun) {
  backendResponse = $input.item.json.dryRunResult;
  executionData = $input.item.json;
} else {
  backendResponse = $input.item.json;
  executionData = $('Enforce Rate Limit and Build Execution Context').item.json;
}

// Detect backend HTTP error codes
const statusCode = backendResponse.statusCode || backendResponse.status || 200;
const isError = statusCode >= 400 || backendResponse.error;

// Determine tool call success
const toolCallSuccess = !isError && !isDryRun
  ? true
  : isDryRun
  ? null // null = not executed
  : false;

// Apply response field mapping if configured
const responseMapping = executionData.resolvedTool?.responseMapping || {};
let normalizedData = backendResponse;

if (Object.keys(responseMapping).length > 0) {
  normalizedData = {};
  for (const [mcpField, backendField] of Object.entries(responseMapping)) {
    normalizedData[mcpField] = backendResponse[backendField] ?? backendResponse[mcpField] ?? null;
  }
}

// Build MCP-compliant tool result
const mcpToolResult = {
  // MCP result schema
  mcpVersion: executionData.mcpRequest?.mcpVersion || '1.0',
  gatewayRequestId: executionData.mcpRequest?.gatewayRequestId,
  requestId: executionData.mcpRequest?.requestId,
  toolName: executionData.mcpRequest?.toolName,
  clientId: executionData.mcpRequest?.clientId,

  // Execution result
  success: toolCallSuccess,
  isDryRun,
  statusCode: isDryRun ? null : statusCode,

  // Tool data
  result: isDryRun ? backendResponse : (isError ? null : normalizedData),
  error: isError ? {
    code: statusCode,
    message: backendResponse.message || backendResponse.error || 'Backend API call failed',
    details: backendResponse.details || null
  } : null,

  // AI verification metadata
  intentVerification: {
    riskLevel: executionData.intentVerification?.riskLevel,
    riskScore: executionData.intentVerification?.riskScore,
    executionRecommendation: executionData.intentVerification?.executionRecommendation,
    piiDetected: executionData.intentVerification?.piiDetected
  },

  // Rate limit info for client
  rateLimitInfo: executionData.rateLimitStatus || null,

  // Timing
  executedAt: new Date().toISOString()
};

return {
  json: {
    mcpToolResult,
    rawBackendResponse: isDryRun ? null : backendResponse,
    executionData
  }
};

const data = $input.item.json;

// Strip internal fields — return only MCP-compliant tool result to client
return {
  json: {
    mcpVersion: data.mcpToolResult.mcpVersion,
    gatewayRequestId: data.mcpToolResult.gatewayRequestId,
    requestId: data.mcpToolResult.requestId,
    toolName: data.mcpToolResult.toolName,
    success: data.mcpToolResult.success,
    isDryRun: data.mcpToolResult.isDryRun,
    result: data.mcpToolResult.result,
    error: data.mcpToolResult.error,
    meta: {
      riskLevel: data.mcpToolResult.intentVerification.riskLevel,
      piiDetected: data.mcpToolResult.intentVerification.piiDetected,
      rateLimitRemaining: data.mcpToolResult.rateLimitInfo?.remaining ?? null,
      executedAt: data.mcpToolResult.executedAt
    }
  }
};
